async (params, browser) => {
  // Open Untappd
  await browser.open(`https://untappd.com/b/beer/${params.beer_id}`)

  // Wait for page
  await browser.waitForSelector('h1, .name, .content', 15000)

  // Let page render
  await browser.wait(2500)

  // Extract data
  const result = await browser.evaluate(`const name = document.querySelector('h1, .name h1')?.textContent?.trim() || ''; const brewery = document.querySelector('.brewery a, h2 a')?.textContent?.trim() || ''; const style = document.querySelector('.style, .beer-style')?.textContent?.trim() || ''; const abv = document.querySelector('.abv, [class*="abv"]')?.textContent?.trim() || ''; const rating = document.querySelector('.num, .rating .num, [class*="rating-num"]')?.textContent?.trim() || ''; const desc = document.querySelector('.beer-descrption, .beer-description, .desc p')?.textContent?.trim()?.slice(0, 500) || ''; return { name, brewery, style, abv, rating, description: desc, url: window.location.href };`)

  return result
}
